import 'package:flutter/material.dart'; import 'package:flutter_map/flutter_map.dart'; import 'package:latlong2/latlong.dart'; import 'package:url_launcher/url_launcher.dart'; import '../../data/datasources/local_pack_datasource.dart'; import '../../data/datasources/field_log_datasource.dart'; import '../../domain/models/field_log.dart'; import '../../engines/bouh_supreme_engine.dart'; import '../widgets/analysis_bottom_sheet.dart';
class MapScreen extends StatefulWidget{final LocalPackDatasource pack; const MapScreen({super.key,required this.pack}); @override State<MapScreen> createState()=>_MapScreenState();}
class _MapScreenState extends State<MapScreen>{final logDs=FieldLogDatasource(); LatLng? selected; bool satellite=true; Future<void> analyze(LatLng p) async{setState(()=>selected=p); final cell=widget.pack.nearestCell(p.latitude,p.longitude); final r=BouhSupremeEngine.analyze(cell); if(!mounted)return; showModalBottomSheet(context:context,isScrollControlled:true,backgroundColor:Colors.transparent,builder:(_)=>AnalysisBottomSheet(cell:cell,result:r,onOpenMaps:()=>launchUrl(Uri.parse('https://www.google.com/maps/search/?api=1&query=${cell.lat},${cell.lon}'),mode:LaunchMode.externalApplication),onSaveLog:()async{await logDs.add(FieldLog(id:DateTime.now().millisecondsSinceEpoch.toString(),lat:cell.lat,lon:cell.lon,decision:r.classLabelAr,ipi:r.ipiScore,createdAt:DateTime.now(),note:r.reasonAr)); if(mounted)ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content:Text('تم حفظ السجل')));},));}
@override Widget build(BuildContext context){final markers=[for(final t in widget.pack.targets) Marker(point:LatLng(t.lat,t.lon),width:42,height:42,child:Tooltip(message:t.nameAr,child:const Icon(Icons.location_on,color:Color(0xFFD4AF37),size:34))), if(selected!=null) Marker(point:selected!,width:42,height:42,child:const Icon(Icons.my_location,color:Colors.cyanAccent,size:32))]; return Stack(children:[FlutterMap(options:MapOptions(initialCenter:const LatLng(20.7805,36.4507),initialZoom:8.2,onLongPress:(_,p)=>analyze(p),onTap:(_,p)=>analyze(p)),children:[TileLayer(urlTemplate:satellite?'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}':'https://tile.openstreetmap.org/{z}/{x}/{y}.png',userAgentPackageName:'com.bouh.gold.pro.ultra',maxZoom:18),MarkerLayer(markers:markers)]),Positioned(top:12,right:12,left:12,child:Card(color:const Color(0xDD07100B),child:Padding(padding:const EdgeInsets.all(10),child:Text(selected==null?'اضغط على الخريطة لتحليل أقرب خلية في Region Pack':'النقطة: ${selected!.latitude.toStringAsFixed(5)}, ${selected!.longitude.toStringAsFixed(5)}')))),Positioned(bottom:16,left:16,child:FloatingActionButton.extended(heroTag:'satToggle',onPressed:()=>setState(()=>satellite=!satellite),icon:const Icon(Icons.layers),label:Text(satellite?'قمر صناعي':'خريطة')))]);}}
